#pragma mark - Pay Method

- (void)setupPaymentMethods:(WBProductModel *)selectProduct {
    NSArray *availableMethods = @[
        @{@"method": @(WBPaymentMethodAliPay), @"view": self.aliPayView},
        @{@"method": @(WBPaymentMethodWechatPay), @"view": self.wechatPayView},
        @{@"method": @(WBPaymentMethodApplePay), @"view": self.applePayView}
    ];

    for (NSDictionary *method in availableMethods) {
        NSNumber *methodNumber = method[@"method"];
        WBPaymentMethod methodValue = (WBPaymentMethod)[methodNumber unsignedIntegerValue];
        WBPaymentMethodView *view = method[@"view"];
        view.hidden = !(self.availablePaymentMethods & methodValue);
    }

    if (selectProduct.discountAmount > 0) {
        BOOL isApplePay = selectProduct.payMethod & WBPaymentMethodApplePay;
        BOOL isSubscription = selectProduct.payMethod & WBPaymentMethodSubscription;
        if (isApplePay && !isSubscription) {
            self.applePayView.hidden = YES;
        }
    }

    // 默认选择第一个可用的支付方式
    for (NSDictionary *method in availableMethods) {
        NSNumber *methodNumber = method[@"method"];
        WBPaymentMethod methodValue = (WBPaymentMethod)[methodNumber unsignedIntegerValue];
        WBPaymentMethodView *view = method[@"view"];
        if ((self.availablePaymentMethods & methodValue) && !view.button.selected) {
            view.button.selected = YES;
            break;  // 选中第一个之后立马结束循环
        }
    }
}


