- (NSString *)getAvailablePromoCountString {
    WBProductModel *selectedProduct = [self getSelectedProductModel];
    [self parseAvailableAndUnavailablePromos];
    if (![self.availablePromos count] || ![WBVipViewController checkIfCouldUsePromo:selectedProduct]) {
        self.promoSectionView.promoUserInfoType = WBPromoUserInfoType_GotNo;
        return @"暂无可用优惠券";
    }

    int availablePromoCount = [self calculateAvailablePromosForProduct:selectedProduct];
    selectedProduct.availablePromoCount = availablePromoCount;

    if (self.payOptionsView.selectedPayMethod == WBPaymentMethodApplePay && [WBVipViewController isAppleNonSubscription:selectedProduct]) {
        selectedProduct.selectedPromoModels = nil;
        selectedProduct.availablePromoCount = 0;
        NSMutableArray *available = [self.availablePromos mutableCopy];
        NSMutableArray *unavailable = [self.unavailablePromos mutableCopy];
        [unavailable addObjectsFromArray:available];
        [available removeAllObjects];
        self.availablePromos = [available copy];
        self.unavailablePromos = [unavailable copy];
    }
    return [self generatePromoCountMessage:selectedProduct.availablePromoCount];
}

- (int)calculateAvailablePromosForProduct:(WBProductModel *)product {
    int availablePromoCount = 0;
    for (WBPromoModel *promo in self.availablePromos) {
        // 苹果连续订阅优惠券
        if ([WBVipViewController isAppleSubscription:product]) {
            if ([WBVipViewController isAppleSubscriptionPromo:promo] && promo.minCharge <= [product.price floatValue]) {
                availablePromoCount++;
            }
        }
        // 普通优惠券
        else {
            if (promo.minCharge > [product.price floatValue] || [WBVipViewController isAppleSubscriptionPromo:promo]) continue;
            availablePromoCount++;
        }
    }
    return availablePromoCount;
}

- (NSString *)generatePromoCountMessage:(NSInteger)promoCount {
    BOOL hasPromos = promoCount != 0;
    self.promoSectionView.promoUserInfoType = hasPromos ? WBPromoUserInfoType_Has : WBPromoUserInfoType_GotNo;

    // 调用 promoUserInfoChange: 来更新 UI 和通知委托
    [self.promoSectionView promoUserInfoChange:hasPromos];

    return hasPromos ? [NSString stringWithFormat:@"有%zd张可用优惠券", promoCount] : @"暂无可用优惠券";
}

- (void)afterSelectPayMethod {
    WBProductModel *selectedProduct = [self getSelectedProductModel];
    selectedProduct.selectedPaymethod = self.payOptionsView.selectedPayMethod;
    selectedProduct.selectedPayMethodId = self.payOptionsView.selectedPayMethodId;
    if (self.payOptionsView.selectedPayMethod == WBPaymentMethodTaoBaoPay) {
//        self.purchaseView.orderView.hidden = YES;
//        self.purchaseView.purchaseButton.hidden = YES;
//        self.purchaseView.jumpButton.hidden = NO;
        self.promoSectionView.hidden = YES;
        [self.purchaseView RefreshUI:self.payOptionsView.selectedPayMethod];
        selectedProduct.selectedPromoModels = nil;
        selectedProduct.availablePromoCount = 0;

    } else {
//        self.purchaseView.orderView.hidden = NO;
//        self.purchaseView.purchaseButton.hidden = NO;
//        self.purchaseView.jumpButton.hidden = YES;
        if (self.payOptionsView.selectedPayMethod == WBPaymentMethodApplePay && [WBVipViewController isAppleNonSubscription:selectedProduct]) {
            selectedProduct.selectedPromoModels = nil;
            selectedProduct.availablePromoCount = 0;
        }
        [self.purchaseView RefreshUI:self.payOptionsView.selectedPayMethod];
        self.promoSectionView.productModel = selectedProduct;
        self.purchaseView.productModel = selectedProduct;
        [self updatePromoUserInfoLabel];
    }

    // 更新布局
    [self updateFloatingViewInnerLayout];
}

- (void)updateFloatingViewInnerLayout {
    [self ensureFloatingViewHierarchyBeforeRelayout];
    [self.floatingView mas_remakeConstraints:^(MASConstraintMaker *make) {
        make.left.right.bottom.equalTo(self.view);
        if (self.promoSectionView.hidden) {
            make.height.mas_equalTo(ZOOM(172));
        } else {
            make.height.mas_equalTo(ZOOM(210));
        }
    }];
    [self.purchaseView mas_remakeConstraints:^(MASConstraintMaker *make) {
        make.left.right.equalTo(self.floatingView);
        if (self.promoSectionView.hidden) {
            make.top.equalTo(self.payOptionsView.mas_bottom).offset(ZOOM(20));
        } else {
            make.top.equalTo(self.promoSectionView.mas_bottom).offset(ZOOM(20));
        }
    }];

    [UIView animateWithDuration:0.3 animations:^{
        [self.view layoutIfNeeded];
    }];
}

- (void)refreshData {
    WBModule currentModule = [self getCurrentModule];
    [self.headerView updateUIWithCurrentModule:currentModule];
    [self.productCollectionView reloadData];

    if (self.productCollectionView.products.count > 0) {
        // 取消之前的选择
        NSArray *selectedItems = [self.productCollectionView indexPathsForSelectedItems];
        [selectedItems enumerateObjectsUsingBlock:^(NSIndexPath *indexPath, NSUInteger idx, BOOL *stop) {
            [self.productCollectionView deselectItemAtIndexPath:indexPath animated:NO];
        }];
        // 默认选中第一个
        NSIndexPath *firstIndexPath = [NSIndexPath indexPathForItem:0 inSection:0];
        [self.productCollectionView selectItemAtIndexPath:firstIndexPath
                                                animated:NO
                                          scrollPosition:UICollectionViewScrollPositionNone];
        [self updatePromoAndPurchaseView:self.currentProducts[0]];
        [self updatePrivilegeViewForSelectedProduct:self.currentProducts[0]];

        self.promoSectionView.userInteractionEnabled = YES;
        self.payOptionsView.userInteractionEnabled = YES;
        self.purchaseView.userInteractionEnabled = YES;
    } else {    // 当前展示货架无商品，禁止商品相关交互
        self.promoSectionView.userInteractionEnabled = NO;
        self.payOptionsView.userInteractionEnabled = NO;
        self.purchaseView.userInteractionEnabled = NO;
    }
}


