- (void)onPaymentSuccess {
    if (!self.paymentSuccessProcessed && self.inFront) {
        [self presentPaymentSuccessUI];
        [self removeConsumedPromosFromProductAndAvailablePromos];
        for (WBProductModel *product in self.productCollectionView.products) { // Clear all selected promos.
            product.selectedPromoModels = nil;
            product.availablePromoCount = 0;
        }
        self.purchaseView.productModel = [self getSelectedProductModel];
        [self loadPromos]; // Reload promos and refresh UI.

        self.paymentSuccessProcessed = YES; // Mark as processed（标记为已处理）
    }
}

- (void)removeConsumedPromosFromProductAndAvailablePromos {
    WBProductModel *purchasedProduct = [WBPaymentManager sharedManager].product;
    if (![purchasedProduct.selectedPromoModels count]) return;
    NSMutableArray<WBPromoModel *> *availablePromoModels = [NSMutableArray arrayWithArray:self.availablePromos];
    for (WBPromoModel *consumedPromoModel in purchasedProduct.selectedPromoModels) {
        [self.availablePromos enumerateObjectsUsingBlock:^(WBPromoModel * _Nonnull availablePromoModel, NSUInteger idx, BOOL * _Nonnull stop) {
            if (![availablePromoModel.code isEqualToString:consumedPromoModel.code] || ![availablePromoModels containsObject:availablePromoModel]) {
                NSParameterAssert(idx != [self.availablePromos count] - 1);
                return;
            }
            [availablePromoModels removeObject:availablePromoModel];
            *stop = true;
        }];
    }

    for (WBProductModel *product in self.allProducts) {
        product.selectedPromoModels = nil;
    }

    self.availablePromos = [availablePromoModels copy];
}


