- (void)ensureFloatingViewHierarchyBeforeRelayout {
    if (!self.isViewLoaded) return;

    if (self.floatingView.superview != self.view) {
        [self.floatingView removeFromSuperview];
        [self.view addSubview:self.floatingView];
    }
    if (self.payOptionsView.superview != self.floatingView) {
        [self.payOptionsView removeFromSuperview];
        [self.floatingView addSubview:self.payOptionsView];
    }
    if (self.promoSectionView.superview != self.floatingView) {
        [self.promoSectionView removeFromSuperview];
        [self.floatingView addSubview:self.promoSectionView];
    }
    if (self.purchaseView.superview != self.floatingView) {
        [self.purchaseView removeFromSuperview];
        [self.floatingView addSubview:self.purchaseView];
    }

    [self.payOptionsView mas_remakeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.floatingView).offset(ZOOM(8));
        make.left.right.equalTo(self.view);
        make.height.mas_equalTo(ZOOM(42));
    }];

    [self.promoSectionView mas_remakeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.payOptionsView.mas_bottom).offset(ZOOM(10));
        make.left.equalTo(self.view).offset(ZOOM(16));
        make.right.equalTo(self.view).offset(ZOOM(-16));
        make.height.mas_equalTo(ZOOM(28));
    }];
}

