#pragma mark - products

- (NSArray<WBProductModel *> *)currentProducts {
    if (!_currentProducts) {
        // 使用 NSPredicate 过滤，筛选 VIP/SVIP 商品
        NSPredicate *predicate;
        if (self.selectedProductType == WBProductTypeSVIP) {
            predicate = [NSPredicate predicateWithFormat:@"(typeFlags & %lu) != 0", WBProductTypeFlagVIPLevel];
        } else {
            predicate = [NSPredicate predicateWithFormat:@"(typeFlags & %lu) = 0", WBProductTypeFlagVIPLevel];
        }
        self.currentProducts = [self.allProducts filteredArrayUsingPredicate:predicate];

        [WBPaymentManager sharedManager];
    }
    return _currentProducts;
}


