- (void)updateWithServerPayMethods:(NSArray<NSDictionary *> *)payMethods {
    NSMutableArray *tempArray = [NSMutableArray array];
    self.selectedPayMethod = WBPaymentMethodNone;

    for (NSDictionary *payMethod in payMethods) {
        NSMutableDictionary *newDict = [NSMutableDictionary dictionary];

        newDict[@"id"] = payMethod[@"id"];
        newDict[@"type"] = payMethod[@"type"];
        newDict[@"showBadge"] = payMethod[@"showBadge"];
        newDict[@"badgeValue"] = payMethod[@"badgeValue"];
        newDict[@"sort"] = payMethod[@"sort"];
        newDict[@"discount"] = payMethod[@"discount"];
        newDict[@"link"] = payMethod[@"link"];

        switch ([newDict[@"type"] integerValue]) {
            case WBPaymentMethodApplePay:
                newDict[@"title"] = @"Apple Pay";
                newDict[@"icon"] = @"ApplePay";
                break;
            case WBPaymentMethodAliPay:
                newDict[@"title"] = @"支付宝";
                newDict[@"icon"] = @"支付宝";
                break;
            case WBPaymentMethodWechatPay:
                newDict[@"title"] = @"微信";
                newDict[@"icon"] = @"微信支付";
                break;
            case WBPaymentMethodTaoBaoPay:
                newDict[@"title"] = @"淘宝";
                newDict[@"icon"] = @"淘宝";
                break;
            default:
                break;
        }

        [tempArray addObject:newDict];
    }

    self.serverPayMethods = [tempArray sortedArrayUsingComparator:^NSComparisonResult(NSDictionary *obj1, NSDictionary *obj2) {
        return [obj1[@"sort"] compare:obj2[@"sort"]];
    }];

    if (self.serverPayMethods.count > 0) {
        NSDictionary *firstMethod = self.serverPayMethods[0];
        self.selectedPayMethod = (WBPaymentMethod)[firstMethod[@"type"] integerValue];
        self.selectedPayMethodName = firstMethod[@"title"];
        self.selectedPayMethodUrl = firstMethod[@"link"];
        self.selectedPayMethodId = firstMethod[@"id"];
    }

    [self updateButtonVisibility];
    [self updateButtonStyles];
}

