@property(nonatomic, strong) UIView *promoLimitTimeContainerView;
@property(nonatomic, strong) UIImageView *promoLimitTimeImageView;
@property(nonatomic, strong) UILabel *promoLimitTimeLabel;
@property(nonatomic, strong) dispatch_source_t countdownTimer; // 存储当前优惠的倒计时

@end

@implementation WBPurchaseSectionView

- (instancetype)initWithFrame:(CGRect)frame {
    if (self = [super initWithFrame:frame]) {
        [self addAllSubviews];
        [self addAllConstraints];
    }
    return self;
}

- (void)setNeedsRefreshUI {
    if (!self.productModel) return;
    [self setProductModel:self.productModel];
}

- (void)RefreshUI:(WBPaymentMethod)PaymentMethod {
    if (PaymentMethod == WBPaymentMethodTaoBaoPay) {
        self.orderView.hidden = YES;
        self.purchaseButton.hidden = YES;
        self.jumpButton.hidden = NO;
        self.discountTipBackImage.hidden = YES;
        self.discountInfo.hidden = YES;
    } else {
        self.orderView.hidden = NO;
        self.purchaseButton.hidden = NO;
        self.jumpButton.hidden = YES;
        self.discountTipBackImage.hidden = NO;
        self.discountInfo.hidden = NO;
    }
}

- (void)setProductModel:(WBProductModel *)productModel {
    _productModel = productModel;
    NSDate *promoExpireDate = productModel.calculatedPromoExpireDate;
    if (promoExpireDate && [promoExpireDate compare:[NSDate date]] == NSOrderedDescending) {
        [self showPromoLimitTimeAndUpdateConstraintsWithPromoExpireDate:promoExpireDate];
    } else {
        [self hidePromoLimitTimeAndUpdateConstraints];
    }
    CGFloat discountedPrice = productModel.discountedPrice;

    if (discountedPrice > 0) {
        NSString *priceString = [NSString stringWithFormat:@"¥%.2f", discountedPrice]; // 强制两位小数
        NSMutableAttributedString *attributedString = [[NSMutableAttributedString alloc] initWithString:priceString];

        // ¥ 符号
        [attributedString addAttribute:NSFontAttributeName
                                 value:WBPrimaryBoldFont(20)
                                 range:NSMakeRange(0, 1)];

        // 整数部分
        NSInteger integerPartLength = priceString.length - 4;
        NSRange integerRange = NSMakeRange(1, integerPartLength);
        [attributedString addAttribute:NSFontAttributeName
                                 value:WBPrimaryBoldFont(30)
                                 range:integerRange];

        // 小数部分
        NSRange decimalRange = NSMakeRange(priceString.length - 3, 3);
        [attributedString addAttribute:NSFontAttributeName
                                 value:WBPrimaryBoldFont(20)
                                 range:decimalRange];

        self.priceLabel.attributedText = attributedString;
    } else {
        self.priceLabel.text = @"价格异常";
    }

    if (productModel.discountAmount) {
        self.discountTipBackImage.hidden = NO;
        self.discountInfo.hidden = NO;
        self.discountInfo.text = [NSString stringWithFormat:@"已优惠¥%g", productModel.discountAmount];
    } else {
        self.discountTipBackImage.hidden = YES;
        self.discountInfo.hidden = YES;
    }
}

- (void)showPromoLimitTimeAndUpdateConstraintsWithPromoExpireDate:(NSDate *)promoExpireDate {
    self.promoLimitTimeDecorationView.hidden = true;    // 暂时隐藏“限时优惠倒计时”视图
    [self countDownPromoExpireDataWithProduct:self.productModel promoExpireDate:promoExpireDate];
}


- (void)countDownPromoExpireDataWithProduct:(WBProductModel *)product promoExpireDate:(NSDate *)promoExpireDate {
    if (product != self.productModel) return;

    // 取消之前的倒计时任务
    if (self.countdownTimer) {
        dispatch_source_cancel(self.countdownTimer);
        self.countdownTimer = nil;
    }

    NSDateComponents *dateComponents = [[NSCalendar currentCalendar] components:(NSCalendarUnitDay | NSCalendarUnitHour | NSCalendarUnitMinute | NSCalendarUnitSecond) fromDate:[NSDate date] toDate:promoExpireDate options:NSCalendarWrapComponents];
    NSString *remainTimeTitle;
    if (dateComponents.day > 0) {
        remainTimeTitle = [NSString stringWithFormat:@"%zd天%zd小时%zd分钟", dateComponents.day, dateComponents.hour, dateComponents.minute];
    } else if (dateComponents.hour > 0) {
        remainTimeTitle = [NSString stringWithFormat:@"%zd小时%zd分钟%zd秒", dateComponents.hour, dateComponents.minute, dateComponents.second];
    } else if (dateComponents.minute > 0) {
        remainTimeTitle = [NSString stringWithFormat:@"%zd分钟%zd秒", dateComponents.minute, dateComponents.second];
    } else if (dateComponents.second > 0) {
        remainTimeTitle = [NSString stringWithFormat:@"%zd秒", dateComponents.second];
    } else {
        [self hidePromoLimitTimeAndUpdateConstraints];
        if (self.delegate && [self.delegate respondsToSelector:@selector(purchaseSectionViewPromoLimitTimeCountdownTimerEndCountDown:)]) {
            [self.delegate purchaseSectionViewPromoLimitTimeCountdownTimerEndCountDown:self];
        }
        return;
    }

